import { Center } from '@chakra-ui/layout';
import { IUserMeResponse } from '@domain/user';
import { ApiClient } from '@service/anedot/client';
import { useAuthStore } from '@state/authStore/useAuthStore';
import { Loading } from '@ui/components/Loading';
import { getApiHostname } from '@utils/getApiHostname';
import { isDevelopment } from '@utils/isDevelopment';
import { isVitePreview } from '@utils/isDevelopment/isVitePreview';
import axios from 'axios';
import { useEffect, useState } from 'react';

const LOGIN_PATH = '/login';
const LOCAL_LOGIN = `http://anedot.me:3000${LOGIN_PATH}`;

interface IProps {
  children: React.ReactNode;
  performRedirect?: boolean;
  showLoading?: boolean;
}

export const AuthenticatedWrapper = ({
  children,
  performRedirect = true,
  showLoading = true,
}: IProps) => {
  const [isLoading, setLoading] = useState<boolean>(true);
  const { setUser, user } = useAuthStore();

  useEffect(() => {
    const loadUser = async () => {
      try {
        const response = await new ApiClient({ performRedirect }).get<IUserMeResponse>(`/me`, {
          baseURL: `${getApiHostname()}/user/v3`,
        });
        const { csrfToken, ...rest } = response;
        axios.defaults.headers.common['X-CSRF-TOKEN'] = csrfToken;
        setUser(rest);
        setLoading(false);
      } catch (_e) {
        if (performRedirect) {
          const path = isDevelopment() || isVitePreview() ? LOCAL_LOGIN : LOGIN_PATH;
          const redirectParams = new URLSearchParams({ return_to: window.location.href });
          window.location.assign(`${path}?${redirectParams.toString()}`);
        } else {
          setLoading(false);
        }
      }
    };

    loadUser();
  }, [performRedirect, setUser]);

  if (showLoading && isLoading) {
    return (
      <Center flex={1} height="100vh">
        <Loading />
      </Center>
    );
  }

  if (performRedirect && !user) {
    // same re-assignment logic as above, see comment there
    window.location.assign(isDevelopment() || isVitePreview() ? LOCAL_LOGIN : LOGIN_PATH);
    return null;
  }

  return <>{children}</>;
};

