import { isDevelopment } from '@utils';
import { useMemo } from 'react';
import { matchPath, RouteObject, useLocation, useRoutes } from 'react-router-dom';
import { AuthenticatedWrapper } from './components/AuthenticatedWrapper';
import { PageTitle } from './components/PageTitle';
import { RollbarWrapper } from './components/RollbarWrapper';
import { useRouteConfig } from './useRouteConfig';

const publicPageRoutes = [
  'events/:actionPageSlug',
  'events/:actionPageSlug/submissions/:submissionId/receipt',
  ':accountSlug/events/:actionPageSlug',
  ':accountSlug/events/:actionPageSlug/submissions/:submissionId/receipt',
  ':actionPageSlug',
  ':actionPageSlug/submissions/:submissionId/receipt',
  ':accountSlug/:actionPageSlug',
  ':accountSlug/:actionPageSlug/submissions/:submissionId/receipt',
];

export const App = () => {
  const routeConfig = useRouteConfig();
  const routes = useRoutes(routeConfig as RouteObject[]);

  const { pathname } = useLocation();

  const isPublicAP = useMemo(
    /*
      Check if current pathname is either a public action page or confirmation page.
      If `isPublicAP` is false, the AuthWrapper will redirect to the /login route.
   */
    () =>
      publicPageRoutes.some((route) => matchPath(route, pathname)) ||
      // TODO: refactor the below condition (combine with the Events conditions above?)
      // to make it more clear how we are gatekeeping ActionPages.
      (isDevelopment() &&
        !!routeConfig
          .find(({ path }) => path === ':accountSlug/:actionPageSlug')
          ?.children?.find(
            ({ index, path }) =>
              index ||
              matchPath(path, pathname)?.pattern.path === 'submissions/:submissionId/receipt'
          )),
    [pathname, routeConfig]
  );

  return (
    <RollbarWrapper>
      <AuthenticatedWrapper performRedirect={!isPublicAP}>
        <PageTitle />
        {routes}
      </AuthenticatedWrapper>
    </RollbarWrapper>
  );
};

export default App;

