import { getApiHostname } from '@utils/getApiHostname';
import { useCallback, useState } from 'react';

export const useDonorSession = () => {
  const [isLoading, setIsLoading] = useState(false);

  const createSession = useCallback((email: string, password: string) => {
    setIsLoading(true);

    return new Promise((resolve, reject) => {
      fetch(`${getApiHostname()}/donor/sessions`, {
        body: JSON.stringify({
          user: { email, password },
        }),
        cache: 'no-cache',
        credentials: 'include',
        headers: {
          Accept: 'application/json',
          'Content-Type': 'application/json',
        },
        method: 'POST',
        mode: 'cors',
        // redirect: 'manual',
      })
        .then((response) => response.json())
        .then((response) =>
          response.error
            ? reject(response.error)
            : response.success
              ? resolve(response.success)
              : reject(response)
        )
        .catch((error) => reject(error))
        .finally(() => setIsLoading(false));
    });
  }, []);

  const logout = useCallback(() => {
    setIsLoading(true);

    return new Promise((resolve, reject) => {
      fetch(`${getApiHostname()}/donor/logout`, {
        cache: 'no-cache',
        credentials: 'include',
        headers: {
          Accept: 'application/json',
          'Content-Type': 'application/json',
        },
        method: 'GET',
        mode: 'cors',
      })
        .then(() => resolve(''))
        .catch((error) => reject(error))
        .finally(() => setIsLoading(false));
    });
  }, []);

  return {
    createSession,
    isLoading,
    logout,
  };
};

