import { PublicActionPage } from '@domain/publicActionPage';
import { resourceKeys } from '@state/cacheHelper/resourceKeys';
import { useCacheHelper } from '@state/cacheHelper/useCacheHelper';
import { useDonorSession } from '@state/donor/sessions/useDonorSession';
import { useFeatureFlag } from '@state/featureFlags/hooks/useFeatureFlag';
import { useGetFocusLoginURL } from '@state/public/logins/focus/queries/useGetFocusLoginURL';
import { useGetDonorProfile } from '@state/user/donor_profile';
import { useQueryParam } from '@state/utils/useQueryParam';
import { formatCurrency } from '@ui/utils/formatCurrency';
import { getBasePaths } from '@ui/utils/getBasePaths';
import { createPersistentDisclosureHook } from '@ui/utils/usePersistentDisclosure';
import { isDevelopment } from '@utils';
import { getApiHostname } from '@utils/getApiHostname';
import { isEventPage } from '@utils/isDonationPage/isDonationPage';
import prependHttp from 'prepend-http';
import { useCallback, useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useSearchParams } from 'react-router-dom';
import { useTotalAmount } from '../../../hooks';

const { secureHostname } = getBasePaths();

type Props = {
  actionPage: PublicActionPage;
  isCustomDomain?: boolean;
  isEmbedded?: boolean;
  isPreview?: boolean;
};

const useLoginDisclosure = createPersistentDisclosureHook('login');

export const useExpressCheckout = ({
  actionPage,
  isCustomDomain,
  isEmbedded,
  isPreview = false,
}: Props) => {
  const enableBankDraft = useFeatureFlag('actionPages2.publicRender.enableBankDraft');
  const enablePlaidLink = useFeatureFlag('settings.usePlaidBankAccountVerification');
  const { isOpen, onClose, onOpen } = useLoginDisclosure();
  const amount = useTotalAmount();
  const { refetch, remove } = useGetDonorProfile({
    enabled: !isPreview,
    performRedirect: false,
    retry: false,
  });
  const { logout } = useDonorSession();
  const { setValue, watch } = useFormContext();
  const expressCheckoutMethod = watch('expressCheckoutMethod');
  const productId = watch('productId');
  const query = useQueryParam();
  const [searchParams, setSearchParams] = useSearchParams();

  const { refreshCache: refreshFeatureFlagCache } = useCacheHelper(
    resourceKeys.featureFlags,
    actionPage.account?.id
  );

  // Store the express checkout method in url params
  useEffect(() => {
    if (expressCheckoutMethod) {
      searchParams.set('express_checkout_method', expressCheckoutMethod);
    } else {
      searchParams.delete('express_checkout_method');
    }

    setSearchParams(searchParams);
  }, [expressCheckoutMethod, searchParams, setSearchParams]);

  useEffect(() => {
    if (query.has('scroll_top')) {
      const content: HTMLDivElement = document.querySelector('#content') as HTMLDivElement;

      if (content) {
        content.scrollTop = parseInt(query.get('scroll_top') ?? '0', 10);
      }
    }
    // run once on mount
  }, []);

  const canBypassForm = useCallback(
    (checkoutOption?: string) => {
      const {
        customFieldPositionsAttributes = [],
        displayCommunicationsConsent,
        displayEmployment,
        requireEmployment,
        requirePhone,
      } = actionPage.fieldConfiguration;

      const opt = checkoutOption || expressCheckoutMethod;

      if (
        requireEmployment ||
        displayEmployment ||
        customFieldPositionsAttributes.length !== 0 ||
        displayCommunicationsConsent
      ) {
        return false;
      }

      switch (opt) {
        case 'applepay': {
          return true;
        }
        case 'googlepay': {
          if (!requirePhone) {
            return true;
          }

          break;
        }
        default:
          break;
      }

      return false;
    },
    [actionPage.fieldConfiguration, expressCheckoutMethod]
  );

  const nextPath = useMemo(() => {
    return secureHostname || isDevelopment()
      ? `/${actionPage.account.slug}/${isEventPage(actionPage.pageType) ? 'events/' : ''}${
          actionPage.slug
        }${window.location.search}`
      : '';
  }, [actionPage.account.slug, actionPage.pageType, actionPage.slug]);

  const next = useMemo(() => {
    const baseURL = isDevelopment() ? 'anedot.me:3001' : secureHostname;

    return nextPath ? `${prependHttp(baseURL!)}${nextPath}` : '';
  }, [nextPath]);

  const { data: { url: ssoLoginURL } = {} } = useGetFocusLoginURL({
    accountSlug: actionPage.account.slug,
    next: nextPath,
  });

  const showSSOLogin = useMemo(
    () => actionPage?.account?.accountConfiguration?.fotfEnabled,
    [actionPage?.account?.accountConfiguration?.fotfEnabled]
  );

  const onSuccess = useCallback(() => {
    refetch();
  }, [refetch]);

  const onLogout = useCallback(async () => {
    await logout();
    setValue('hasValidDonorPaymentMethod', false);
    const attributes = actionPage.paymentConfiguration || { creditCardEnabled: false };

    const paymentType = attributes.creditCardEnabled
      ? 'credit_card'
      : enableBankDraft
        ? enablePlaidLink
          ? 'plaid_bank_account'
          : 'bank_account'
        : '';

    setValue('type', paymentType);
    remove();
    await refetch();
    refreshFeatureFlagCache();
  }, [
    logout,
    setValue,
    actionPage.paymentConfiguration,
    enableBankDraft,
    enablePlaidLink,
    remove,
    refetch,
    refreshFeatureFlagCache,
  ]);

  const redirectToAnedotLogin = useCallback(() => {
    const url = new URL(next);

    if (amount) {
      url.searchParams.set('amount', formatCurrency(amount).replace(/[$,]/g, ''));
    }

    if (productId) {
      url.searchParams.set('product_id', productId);
    }

    url.searchParams.set(
      'scroll_top',
      document.querySelector('#content')?.scrollTop?.toString() ?? '0'
    );

    window.location.assign(
      `${
        isDevelopment() ? 'http://anedot.me:3000' : getApiHostname()
      }/login?return_to=${encodeURIComponent(url.toString())}`
    );
  }, [amount, next, productId]);

  const redirectToSSOLogin = useCallback(() => {
    window.location.assign(ssoLoginURL!);
  }, [ssoLoginURL]);

  const onClickLogin = useCallback(() => {
    if (showSSOLogin) {
      onOpen();
    } else {
      redirectToAnedotLogin();
    }
  }, [onOpen, redirectToAnedotLogin, showSSOLogin]);

  const redirectIfRequired = useCallback(
    (method: string) => {
      if (next) {
        const url = new URL(next);
        url.searchParams.set('express_checkout_method', method);
        url.searchParams.set('amount', formatCurrency(amount).replace(/[$,]/g, ''));
        url.searchParams.delete('embed');

        if (productId) {
          url.searchParams.set('product_id', productId);
        }

        url.searchParams.set(
          'scroll_top',
          document.querySelector('#content')?.scrollTop?.toString() ?? '0'
        );

        if (isEmbedded) {
          window.open(url, '_blank')?.focus();
        } else if (isCustomDomain) {
          window.location.assign(url);
        }
      }
    },
    [amount, isCustomDomain, isEmbedded, next, productId]
  );

  return {
    canBypassForm,
    isOpen,
    onClickLogin,
    onClose,
    onLogout,
    onOpen,
    onSuccess,
    redirectIfRequired,
    redirectToAnedotLogin,
    redirectToSSOLogin,
    showSSOLogin,
  };
};

